define([],function(){return{getRandomString(){if(window.crypto&&window.crypto.getRandomValues){const t=window.crypto.getRandomValues(new Uint32Array(3));return Array.from(t).map(t=>t.toString(36)).join("")}return(Math.random()*Date.now()).toString(36)},getFileName(t="webm"){const n=new Date,e=`RecordRTC-${n.getUTCFullYear()}${n.getUTCMonth()}${n.getUTCDate()}`;return`${e}-${this.getRandomString()}.${t}`},stringify:t=>Object.entries(t).filter(t=>"function"!=typeof t[1]).map(([t,n])=>`${t}: ${n}`).join(", ")}});